from collections import Counter

class Solution:
    def isPossibleToRearrange(self, s, t, k):
        n = len(s)
        L = n // k
        s_chunks = [s[i:i + L] for i in range(0, n, L)]
        t_chunks = [t[i:i + L] for i in range(0, n, L)]
        return Counter(s_chunks) == Counter(t_chunks)

