var isPossibleToRearrange = function(s, t, k) {
    const n = s.length;
    const L = Math.floor(n / k);
    const count = new Map();
    for (let i = 0; i < n; i += L) {
        const chunk = s.slice(i, i + L);
        count.set(chunk, (count.get(chunk) || 0) + 1);
    }
    for (let i = 0; i < n; i += L) {
        const chunk = t.slice(i, i + L);
        const c = count.get(chunk) || 0;
        if (c === 0) return false;
        count.set(chunk, c - 1);
    }
    for (const v of count.values()) {
        if (v !== 0) return false;
    }
    return true;
};
